import json
from pathlib import Path

class ConfigParser:
    def parse_file(self, filepath: str) -> dict:
        try:
            path = Path(filepath).resolve(strict=True)
            with open(path, 'r', encoding='utf-8') as file:
                return json.load(file)
        except FileNotFoundError:
            raise ValueError(f"File not found: {filepath}")
        except json.JSONDecodeError as e:
            raise ValueError(f"Malformed JSON in file {filepath}: {e}")

    def parse_string(self, json_str: str) -> dict:
        try:
            return json.loads(json_str)
        except json.JSONDecodeError as e:
            raise ValueError(f"Malformed JSON string: {e}")

from typing import Dict, Callable, List
from .validation_error import ValidationError

class CustomRuleRegistry:
    def __init__(self):
        self.rules: Dict[str, Callable] = {}

    def register(self, rule_id: str, func: Callable[[Dict], List[ValidationError]]):
        self.rules[rule_id] = func

    def run_all(self, config: Dict) -> List[ValidationError]:
        return reduce(lambda acc, rule: acc + rule(config), self.rules.values(), [])

