import pytest
from your_module import SchemaValidator, ValidationResult, ValidationError

schema = {
    "type": "object",
    "properties": {
        "name": {"type": "string"},
        "age": {"type": "integer"}
    },
    "required": ["name", "age"]
}

def test_validate_valid_config():
    validator = SchemaValidator(schema)
    config = {"name": "John", "age": 30}
    result = validator.validate(config)
    assert isinstance(result, ValidationResult)
    assert result.is_valid
    assert result.errors == []

def test_validate_invalid_config_missing_field():
    validator = SchemaValidator(schema)
    config = {"name": "John"}
    result = validator.validate(config)
    assert isinstance(result, ValidationResult)
    assert not result.is_valid
    assert len(result.errors) == 1
    assert result.errors[0].path == 'age'
    assert 'is a required property' in result.errors[0].message

def test_validate_invalid_config_wrong_type():
    validator = SchemaValidator(schema)
    config = {"name": "John", "age": "thirty"}
    result = validator.validate(config)
    assert isinstance(result, ValidationResult)
    assert not result.is_valid
    assert len(result.errors) == 1
    assert result.errors[0].path == 'age'
    assert 'is not of type' in result.errors[0].message

def test_custom_rule_registration_and_execution():
    def custom_rule(config):
        if config.get('age') < 18:
            return [ValidationError(path='age', message='Age must be at least 18')]
        return []

    validator = SchemaValidator(schema)
    validator.custom_rules.register('age_check', custom_rule)
    config = {"name": "John", "age": 17}
    result = validator.validate(config)
    assert isinstance(result, ValidationResult)
    assert not result.is_valid
    assert len(result.errors) == 2
    assert result.errors[1].path == 'age'
    assert result.errors[1].message == 'Age must be at least 18'
